const base64Data = $input.item.json.base64 || '';
const base64String = base64Data.includes('base64,') ? base64Data.split('base64,')[1] : base64Data;
const buffer = Buffer.from(base64String, 'base64');

let mimeType = $input.item.json.mimetype || 'audio/ogg';
if (base64Data.includes('data:') && base64Data.includes(';base64,')) {
  mimeType = base64Data.split(';base64,')[0].replace('data:', '');
}

const baseMime = mimeType.split(';')[0].trim().toLowerCase();
let extension = 'ogg';
if (baseMime === 'audio/mp4' || baseMime === 'video/mp4') {
  extension = 'mp4';
} else if (baseMime === 'audio/mpeg' || baseMime === 'audio/mp3') {
  extension = 'mp3';
} else if (baseMime === 'audio/wav') {
  extension = 'wav';
} else if (baseMime === 'audio/webm') {
  extension = 'webm';
} else if (baseMime === 'audio/m4a') {
  extension = 'm4a';
} else if (baseMime === 'audio/oga') {
  extension = 'oga';
}

const binaryData = await this.helpers.prepareBinaryData(buffer, `audio.${extension}`, baseMime);
return {
  json: $input.item.json,
  binary: {
    data: binaryData
  }
};

